// ══════════════════════════════════════════════════
// FIRMOGRAPHIC SCORER — Company fit vs ICP
// ══════════════════════════════════════════════════

const lead = $input.first().json;
const company = lead.company || {};

// ── ICP Configuration ──────────────────────────
const ICP = {
  targetIndustries: ['saas', 'technology', 'software', 'financial services',
    'healthcare technology', 'e-commerce', 'digital marketing',
    'professional services', 'manufacturing'],
  minEmployees: 20,
  maxEmployees: 5000,
  preferredFunding: ['series a', 'series b', 'series c', 'growth', 'public'],
  targetCountries: ['US', 'CA', 'UK', 'AU', 'DE', 'FR', 'NL'],
  positiveTech: ['salesforce', 'hubspot', 'outreach', 'salesloft', 'gong',
    'zoominfo', 'apollo', '6sense', 'drift', 'intercom',
    'marketo', 'pardot', 'zapier', 'make', 'n8n'],
};

let score = 0;
const breakdown = {};

// Industry (0-30)
let industryScore = 0;
if (company.industry) {
  const ind = company.industry.toLowerCase();
  if (ICP.targetIndustries.some(t => ind.includes(t) || t.includes(ind))) {
    industryScore = 30;
  } else if (company.sub_industry) {
    const sub = company.sub_industry.toLowerCase();
    if (ICP.targetIndustries.some(t => sub.includes(t))) industryScore = 20;
  }
}
breakdown.industry = { score: industryScore, max: 30, value: company.industry };
score += industryScore;

// Employee Count (0-25)
let empScore = 0;
if (company.employee_count) {
  const count = company.employee_count;
  if (count >= ICP.minEmployees && count <= ICP.maxEmployees) {
    const sweet = (ICP.minEmployees + ICP.maxEmployees) / 2;
    const distance = Math.abs(count - sweet) / sweet;
    empScore = Math.round(25 * Math.max(0, 1 - distance * 0.5));
  } else if (count < ICP.minEmployees) {
    empScore = count / ICP.minEmployees > 0.3 ? Math.round(25 * (count / ICP.minEmployees) * 0.5) : 0;
  } else {
    empScore = 12;
  }
}
breakdown.employees = { score: empScore, max: 25, value: company.employee_count };
score += empScore;

// Funding (0-15)
let fundScore = 0;
if (company.funding_stage) {
  const stage = company.funding_stage.toLowerCase();
  if (ICP.preferredFunding.some(f => stage.includes(f))) fundScore = 15;
  else fundScore = 5;
}
breakdown.funding = { score: fundScore, max: 15, value: company.funding_stage };
score += fundScore;

// Geography (0-15)
let geoScore = 0;
if (company.headquarters_country) {
  geoScore = ICP.targetCountries.includes(company.headquarters_country.toUpperCase()) ? 15 : 5;
}
breakdown.geography = { score: geoScore, max: 15, value: company.headquarters_country };
score += geoScore;

// Tech Stack (0-15)
let techScore = 0;
const techMatches = [];
if (company.technologies && company.technologies.length > 0) {
  const techLower = company.technologies.map(t => t.toLowerCase());
  for (const target of ICP.positiveTech) {
    if (techLower.includes(target.toLowerCase())) techMatches.push(target);
  }
  if (techMatches.length > 0) {
    techScore = Math.min(15, 5 + (techMatches.length - 1) * 3.5);
  }
}
breakdown.tech_stack = { score: Math.round(techScore), max: 15, matches: techMatches };
score += Math.round(techScore);

return [{ json: { ...lead, _scores: { firmographic: { score: Math.min(score, 100), breakdown } } } }];

// ══════════════════════════════════════════════════
// DEMOGRAPHIC SCORER — Contact fit vs buyer persona
// ══════════════════════════════════════════════════

const lead = $input.first().json;
const contact = lead.contact || {};

const ICP_TITLES = ['vp of sales', 'vp sales', 'head of sales', 'sales director',
  'chief revenue officer', 'cro', 'vp revenue operations',
  'head of revenue operations', 'director of sales operations',
  'vp of business development', 'head of growth', 'coo'];
const ICP_DEPTS = ['sales', 'revenue operations', 'business development', 'growth'];

let score = 0;
const breakdown = {};

// Seniority (0-30)
const seniorityMap = { c_level: 30, vp: 28, director: 22, manager: 14, senior_ic: 8, ic: 4, unknown: 0 };
const senScore = seniorityMap[contact.seniority] || 0;
breakdown.seniority = { score: senScore, max: 30, value: contact.seniority };
score += senScore;

// Title Match (0-25)
let titleScore = 0;
if (contact.normalized_title) {
  const titleLower = contact.normalized_title.toLowerCase();
  if (ICP_TITLES.some(t => t === titleLower)) {
    titleScore = 25;
  } else {
    const titleWords = new Set(titleLower.split(/\s+/));
    const stopWords = new Set(['of', 'the', 'and', 'a', 'in', 'for']);
    let bestOverlap = 0;
    for (const target of ICP_TITLES) {
      const targetWords = new Set(target.split(/\s+/));
      const meaningful = [...titleWords].filter(w => targetWords.has(w) && !stopWords.has(w));
      bestOverlap = Math.max(bestOverlap, meaningful.length);
    }
    if (bestOverlap >= 2) titleScore = 20;
    else if (bestOverlap >= 1) titleScore = 15;
  }
}
breakdown.title = { score: titleScore, max: 25, value: contact.normalized_title };
score += titleScore;

// Department (0-20)
let deptScore = 0;
if (contact.department) {
  const deptLower = contact.department.toLowerCase();
  if (ICP_DEPTS.some(d => deptLower.includes(d) || d.includes(deptLower))) {
    deptScore = 20;
  } else if (['marketing', 'operations', 'strategy', 'customer success'].some(a => deptLower.includes(a))) {
    deptScore = 8;
  }
}
breakdown.department = { score: deptScore, max: 20, value: contact.department };
score += deptScore;

// Decision Maker (0-15)
const dmScore = contact.is_decision_maker ? 15 : 0;
breakdown.decision_maker = { score: dmScore, max: 15, value: contact.is_decision_maker };
score += dmScore;

// Completeness (0-10)
const fields = [contact.full_name, contact.normalized_title, contact.department,
  contact.linkedin_url, contact.phone_direct, contact.location_city];
const filled = fields.filter(f => f).length;
const compScore = Math.round((filled / fields.length) * 10);
breakdown.completeness = { score: compScore, max: 10, filled, total: fields.length };
score += compScore;

lead._scores.demographic = { score: Math.min(score, 100), breakdown };
return [{ json: lead }];

// ══════════════════════════════════════════════════
// BEHAVIORAL SCORER — Engagement & intent signals
// ══════════════════════════════════════════════════

const lead = $input.first().json;
const raw = lead.raw_lead || {};

const SOURCE_SCORES = { referral: 25, web_form: 20, chat_widget: 18, linkedin: 15, email: 12, event: 10, api: 8 };
const HIGH_INTENT = ['pricing', 'demo', 'trial', 'buy', 'purchase', 'implement', 'migrate', 'replace', 'budget', 'timeline', 'roi', 'cost'];
const MED_INTENT = ['interested', 'learn more', 'information', 'compare', 'evaluate', 'automate', 'streamline', 'improve'];

let score = 0;
const breakdown = {};

// Source (0-25)
const srcScore = SOURCE_SCORES[raw.source] || 5;
breakdown.source = { score: srcScore, max: 25, value: raw.source };
score += srcScore;

// Message Intent (0-30)
let msgScore = 0;
const signals = [];
if (raw.message) {
  const msgLower = raw.message.toLowerCase();
  const highMatches = HIGH_INTENT.filter(kw => msgLower.includes(kw));
  const medMatches = MED_INTENT.filter(kw => msgLower.includes(kw));
  if (highMatches.length > 0) {
    msgScore = Math.min(30, 20 + highMatches.length * 3);
    signals.push(...highMatches.slice(0, 3));
  } else if (medMatches.length > 0) {
    msgScore = Math.min(20, 10 + medMatches.length * 3);
    signals.push(...medMatches.slice(0, 3));
  } else if (raw.message.length > 50) {
    msgScore = 8;
  } else {
    msgScore = 3;
  }
}
breakdown.message_intent = { score: msgScore, max: 30, signals };
score += msgScore;

// UTM (0-20)
let utmScore = 0;
if (raw.utm_source) {
  if (['cpc', 'paid', 'ppc'].includes(raw.utm_medium)) utmScore += 12;
  else if (['email', 'social'].includes(raw.utm_medium)) utmScore += 8;
  else utmScore += 4;
  if (raw.utm_campaign) {
    const camp = raw.utm_campaign.toLowerCase();
    if (['demo', 'trial', 'pricing', 'bottom-funnel'].some(k => camp.includes(k))) utmScore += 8;
    else if (['solution', 'product', 'comparison'].some(k => camp.includes(k))) utmScore += 5;
  }
}
breakdown.utm = { score: Math.min(utmScore, 20), max: 20 };
score += Math.min(utmScore, 20);

// Page Intent (0-15)
let pageScore = 0;
if (raw.page_url) {
  const url = raw.page_url.toLowerCase();
  if (['/pricing', '/demo', '/trial', '/contact-sales', '/request-demo', '/book-a-call'].some(p => url.includes(p))) pageScore = 15;
  else if (['/solutions', '/product', '/features', '/case-studies'].some(p => url.includes(p))) pageScore = 10;
  else pageScore = 3;
}
breakdown.page_intent = { score: pageScore, max: 15 };
score += pageScore;

// Timing (0-10)
breakdown.timing = { score: 5, max: 10 };
score += 5;

lead._scores.behavioral = { score: Math.min(score, 100), breakdown };
return [{ json: lead }];

// ══════════════════════════════════════════════════
// AI FIT SCORER — Uses LLM analysis from Research Agent
// ══════════════════════════════════════════════════

const lead = $input.first().json;
const ai = lead.ai_analysis;

let score = 0;
const breakdown = {};

if (!ai) {
  // No AI analysis — use data confidence as proxy
  score = Math.round((lead.overall_data_confidence || 0) * 40);
  breakdown.note = 'No AI analysis available — using data confidence as proxy';
} else {
  // ICP Fit (0-40)
  const icpScore = Math.round((ai.icp_fit_score || 0) * 40);
  breakdown.icp_fit = { score: icpScore, max: 40 };
  score += icpScore;

  // Buying Signals (0-25)
  let sigScore = 0;
  const strengthMap = { strong: 10, moderate: 5, weak: 2 };
  for (const sig of (ai.buying_signals || []).slice(0, 5)) {
    sigScore += strengthMap[sig.strength] || 2;
  }
  sigScore = Math.min(sigScore, 25);
  breakdown.buying_signals = { score: sigScore, max: 25, count: (ai.buying_signals || []).length };
  score += sigScore;

  // Pain Points (0-20)
  let painScore = 0;
  const relMap = { high: 8, medium: 4, low: 1.5 };
  for (const pp of (ai.pain_points || []).slice(0, 5)) {
    painScore += relMap[pp.relevance_to_product] || 1.5;
  }
  painScore = Math.min(painScore, 20);
  breakdown.pain_points = { score: Math.round(painScore), max: 20 };
  score += Math.round(painScore);

  // Urgency (0-15)
  const urgencyMap = { immediate: 15, near_term: 10, exploratory: 5, not_ready: 1 };
  const urgScore = urgencyMap[ai.urgency_assessment] || 3;
  breakdown.urgency = { score: urgScore, max: 15, value: ai.urgency_assessment };
  score += urgScore;
}

lead._scores.ai_fit = { score: Math.min(score, 100), breakdown };
return [{ json: lead }];

// ══════════════════════════════════════════════════
// COMPOSITE SCORE + DECISION ENGINE
// ══════════════════════════════════════════════════

const lead = $input.first().json;
const s = lead._scores;

// ── Weights ─────────────────────────────────────
const W = { firm: 0.30, demo: 0.25, behav: 0.20, ai: 0.25 };

// ── Base weighted sum ───────────────────────────
let composite = (
  (s.firmographic?.score || 0) * W.firm +
  (s.demographic?.score || 0) * W.demo +
  (s.behavioral?.score || 0) * W.behav +
  (s.ai_fit?.score || 0) * W.ai
);

// ── Bonuses ─────────────────────────────────────
let bonus = 0;
const contact = lead.contact || {};
const ai = lead.ai_analysis;

// Decision maker at C/VP level with good company fit
if (contact.is_decision_maker
    && ['c_level', 'vp'].includes(contact.seniority)
    && (s.firmographic?.score || 0) >= 60) {
  bonus += 8;
}

// Multiple strong buying signals
if (ai?.buying_signals) {
  const strong = ai.buying_signals.filter(s => s.strength === 'strong');
  if (strong.length >= 2) bonus += 5;
}

// Immediate urgency
if (ai?.urgency_assessment === 'immediate') bonus += 5;

// Hiring in sales (growth signal)
if (lead.company?.hiring_signals) {
  const salesHiring = lead.company.hiring_signals.filter(h =>
    /sales|revenue|growth|account exec/i.test(h));
  if (salesHiring.length > 0) bonus += 3;
}

// ── Penalties ───────────────────────────────────
let penalty = 0;
if ((lead.flags || []).includes('free_email')) penalty += 10;
if ((lead.overall_data_confidence || 0) < 0.3) penalty += 8;
else if ((lead.overall_data_confidence || 0) < 0.5) penalty += 4;
if (!lead.company) penalty += 12;
if (contact && !contact.phone_direct && !contact.linkedin_url) penalty += 3;

composite = Math.max(0, Math.min(100, composite + bonus - penalty));

// ── Temperature ─────────────────────────────────
let temperature;
if (composite >= 80) temperature = 'hot';
else if (composite >= 60) temperature = 'warm';
else if (composite >= 40) temperature = 'cool';
else temperature = 'cold';

// ── Hard Disqualifiers ──────────────────────────
let decision, decisionReason;
const flags = lead.flags || [];

if (flags.includes('no_identifiers')) {
  decision = 'disqualified';
  decisionReason = 'No email or company domain';
} else if (lead.company?.employee_count < 5 && !lead.company?.funding_stage) {
  decision = 'disqualified';
  decisionReason = `Company too small (${lead.company?.employee_count} employees)`;
} else if (composite >= 75) {
  decision = 'qualified';
  decisionReason = 'High composite score — auto-qualified';
} else if (composite >= 45) {
  // Context-dependent middle zone
  if (contact.is_decision_maker
      && ['c_level', 'vp'].includes(contact.seniority)
      && (s.firmographic?.breakdown?.industry?.score || 0) >= 20) {
    decision = 'qualified';
    decisionReason = 'Decision maker at ICP company — upgraded';
  } else if (lead.needs_human_review || (lead.overall_data_confidence || 0) < 0.5) {
    decision = 'needs_review';
    decisionReason = 'Mid-range score with incomplete data';
  } else {
    decision = 'nurture';
    decisionReason = 'Score in nurture range — enroll in sequence';
  }
} else {
  if ((lead.overall_data_confidence || 0) < 0.3 && !flags.includes('no_identifiers')) {
    decision = 'needs_review';
    decisionReason = 'Low score + low confidence — review before discarding';
  } else {
    decision = 'disqualified';
    decisionReason = 'Below qualification threshold';
  }
}

// ── Output ──────────────────────────────────────
const result = {
  enriched_lead: lead,
  firmographic_score: s.firmographic?.score || 0,
  demographic_score: s.demographic?.score || 0,
  behavioral_score: s.behavioral?.score || 0,
  ai_fit_score: s.ai_fit?.score || 0,
  composite_score: Math.round(composite * 10) / 10,
  temperature: temperature,
  decision: decision,
  decision_reasoning: decisionReason,
  bonus_applied: bonus,
  penalty_applied: penalty,
  scored_at: new Date().toISOString(),
  scoring_model_version: 'v1.0',
};

return [{ json: result }];
